+  url: string;
+  body: WebhookBody;
+}
+
+/** The JSON body POSTed to the webhook URL. */
+export interface WebhookBody {
+  notificationType: string;
+  subject: string;
+  body: string;
+  metadata?: Record<string, unknown>;
+  timestamp: string;
+}
+
+/** Record of a delivered webhook, including delivery metadata. */
+export interface DeliveredWebhook {
+  url: string;
+  requestBody: WebhookBody;
+  deliveredAt: Date;
+  deliveryId: string;
+}
+
+/**
+ * Transport interface for pluggable webhook delivery.
+ * Implement this to integrate with real HTTP clients.
+ */
+export interface WebhookTransport {
+  post(request: WebhookRequest): Promise<{ deliveryId: string }>;
+}
+
+/**
+ * In-memory transport that stores webhook deliveries instead of sending them.
+ * Used by default for testing and development.
+ */
