import { Logger } from '../utils/logger.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';

/** Represents a formatted webhook request ready for delivery. */
export interface WebhookRequest {
  url: string;
  body: WebhookBody;
}

/** The JSON body POSTed to the webhook URL. */
export interface WebhookBody {
  notificationType: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/** Record of a delivered webhook, including delivery metadata. */
export interface DeliveredWebhook {
  url: string;
  requestBody: WebhookBody;
  deliveredAt: Date;
  deliveryId: string;
}

/**
 * Transport interface for pluggable webhook delivery.
 * Implement this to integrate with real HTTP clients.
 */
export interface WebhookTransport {
  post(request: WebhookRequest): Promise<{ deliveryId: string }>;
}

/**
 * In-memory transport that stores webhook deliveries instead of sending them.
 * Used by default for testing and development.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private counter = 0;

  async post(request: WebhookRequest): Promise<{ deliveryId: string }> {
    this.counter++;
    return { deliveryId: `whk-${String(this.counter).padStart(6, '0')}` };
  }
}

/** Validate that a string looks like a URL. */
function isValidUrl(url: string): boolean {
  return /^https?:\/\/[^\s]+$/.test(url);
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveredWebhooks: DeliveredWebhook[] = [];
  private transport: WebhookTransport;

  constructor(transport?: WebhookTransport) {
    this.transport = transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Format a notification payload into a webhook request body.
   */
  formatPayload(payload: NotificationPayload): WebhookBody {
    return {
      notificationType: payload.notificationType,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Resolve and validate the recipient webhook URL.
   * Returns the validated URL or null if invalid.
   */
  resolveRecipient(payload: NotificationPayload): string | null {
    const url = payload.recipient.trim();

    if (!url) {
      this.logger.warn('Empty webhook URL');
      return null;
    }

    if (!isValidUrl(url)) {
      this.logger.warn(`Invalid webhook URL: ${url}`);
      return null;
    }

    return url;
  }

  /**
   * Send a webhook notification.
   * Validates the URL, formats the payload, and delivers via transport.
   * Never throws — returns { success: false } on failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const resolvedUrl = this.resolveRecipient(payload);

      if (!resolvedUrl) {
        return {
          success: false,
          channel: 'webhook',
          message: `Invalid webhook URL: ${payload.recipient}`,
        };
      }

      const webhookBody = this.formatPayload(payload);
      const request: WebhookRequest = { url: resolvedUrl, body: webhookBody };

      this.logger.info(`Sending webhook to ${resolvedUrl}: ${webhookBody.subject}`);

      const { deliveryId } = await this.transport.post(request);

      const record: DeliveredWebhook = {
        url: resolvedUrl,
        requestBody: webhookBody,
        deliveredAt: new Date(),
        deliveryId,
      };

      this.deliveredWebhooks.push(record);

      return {
        success: true,
        channel: 'webhook',
        message: `Webhook delivered to ${resolvedUrl} (${deliveryId})`,
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Failed to send webhook to ${payload.recipient}: ${message}`);
      return {
        success: false,
        channel: 'webhook',
        message,
      };
    }
  }

  /**
   * Get all webhooks delivered through this adapter. Useful for testing.
   */
  getDeliveredWebhooks(): DeliveredWebhook[] {
    return [...this.deliveredWebhooks];
  }

  /**
   * Clear delivered webhook history. Useful for testing.
   */
  clearDeliveredWebhooks(): void {
    this.deliveredWebhooks = [];
  }
