  });

  describe('custom transport', () => {
    it('should use injected transport', async () => {
      const calls: WebhookRequest[] = [];
      const customTransport: WebhookTransport = {
        async post(request: WebhookRequest) {
          calls.push(request);
          return { deliveryId: 'custom-001' };
        },
      };

      const customAdapter = new WebhookAdapter(customTransport);
      await customAdapter.send(makePayload());

      expect(calls).toHaveLength(1);
      expect(calls[0]?.url).toBe('https://example.com/webhook');

      const delivered = customAdapter.getDeliveredWebhooks();
      expect(delivered[0]?.deliveryId).toBe('custom-001');
    });
  });

  describe('getDeliveredWebhooks and clearDeliveredWebhooks', () => {
    it('should return a copy of delivered webhooks', async () => {
      await adapter.send(makePayload());
      const webhooks1 = adapter.getDeliveredWebhooks();
      const webhooks2 = adapter.getDeliveredWebhooks();
      expect(webhooks1).toEqual(webhooks2);
      expect(webhooks1).not.toBe(webhooks2);
    });

    it('should clear delivered webhooks', async () => {
      await adapter.send(makePayload());
      expect(adapter.getDeliveredWebhooks()).toHaveLength(1);

      adapter.clearDeliveredWebhooks();
      expect(adapter.getDeliveredWebhooks()).toHaveLength(0);
    });
  });
});

describe('InMemoryWebhookTransport', () => {
  it('should return sequential delivery IDs', async () => {
    const transport = new InMemoryWebhookTransport();
    const r1 = await transport.post({ url: 'https://a.com', body: { notificationType: 'system-alert', subject: 'S', body: 'B', timestamp: new Date().toISOString() } });
    const r2 = await transport.post({ url: 'https://b.com', body: { notificationType: 'system-alert', subject: 'S', body: 'B', timestamp: new Date().toISOString() } });

    expect(r1.deliveryId).toBe('whk-000001');
    expect(r2.deliveryId).toBe('whk-000002');
  });
});

